import sys, urllib.request, urllib.error
base='http://localhost:5000'
paths=['/','/page','/admin','/login','/logout','/api','/upload','/download','/flag','/secret','/hint','/robots.txt','/sitemap.xml','/console','/debug','/source','/src','/config','/status','/health','/static','/static/js/app.js','/static/js/main.js','/static/app.js','/read','/view','/file','/files','/archive','/api/flag','/index','/home','/about','/contact','/search','/test','/dev','/__debugger__','/__debugger__/?cmd=help','/__debugger__?cmd=help','/traceback','/python','/eval','/exec','/ping']
for p in paths:
    url=base+p
    try:
        with urllib.request.urlopen(url) as r:
            print(r.status, len(r.read()), p)
    except urllib.error.HTTPError as e:
        # print if not 404
        if e.code != 404:
            print('ERR', e.code, p)
    except Exception as ex:
        print('EXC', type(ex).__name__, p)

